var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"예정대로 건강한 아이가 태어난 것 같군요.","JPN":"予定どおり、健康な子どもが生まれたようですね。","ENG":"I see your baby is healthy. As expected.","TWN":"似乎如預料中的生出個健康的寶寶呢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L5_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"예, 당주님께서 당주 자리에 걸맞은 아이를 낳을 것이라 예견하셨으니 당연한 결과이지요.","JPN":"はい、ご当主が当主として相応しい子を産むと予言なさいましたので当然の結果です。","ENG":"Yes, it is obviously the sufficient baby that you have foreseen.","TWN":"是，我早就預知堂主會生出能夠繼承堂主位置的孩子，這是理所當然的結果。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"하야미 공? 갑자기 왜 그러시나요?","JPN":"速水様？　急にどうされましたか？","ENG":"Is something bothering you, Dame Kanade?","TWN":"速水？怎麼不說話？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"느낌이 이상합니다.","JPN":"おかしいです。","ENG":"I have a strange feeling.","TWN":"我有不好的預感。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"당주님!","JPN":"ご当主様！","ENG":"My lady!","TWN":"堂主！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"산파, 이건……?","JPN":"産婆、これは……？","ENG":"What is this...?","TWN":"產婆，這是……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOC_NPC_NANAHARA_NULL","text":{"KOREA":"그, 그게…… 쌍둥이입니다.","JPN":"そ、それが……双子でございます。","ENG":"Th-the baby... They're twins.","TWN":"是，是……雙胞胎。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOC_NPC_NANAHARA_NULL","text":{"KOREA":"하지만 두 번째 아이는 나올 때부터 숨을 쉬지 않고 있습니다.","JPN":"ですが、2番目の子は出てきた時から息をしておりません。","ENG":"But the second child hasn't been breathing since she came out.","TWN":"可是第二個一生出來就沒有呼吸。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"살릴 방법은 없는 것인가?","JPN":"蘇生させる方法はないのか？","ENG":"Is there any way to save the child?","TWN":"沒辦法救嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOC_NPC_NANAHARA_NULL","text":{"KOREA":"당장 할 수 있는 시도는 모두 해봤지만…… 소용없었습니다.","JPN":"今できることはすべて試してみたのですが……だめでした。","ENG":"I tried the best I could... but I failed.","TWN":"能做的我都做了……無奈還是回天乏術。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당초 1년 전 당주께서 출산을 예견한 아이는 한 명뿐이었습니다.","JPN":"そもそも1年前にご当主が出産を予言した子は一人だけでした。","ENG":"Lady Nanahara had only seen one child in her future.","TWN":"一年前我就看見堂主只會生出一個孩子，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"두 번째 아이의 죽음은 처음부터 정해진 운명인 것이지요.","JPN":"2番目の子の死は最初から定められた運命なのでしょう。","ENG":"Which means that the other child’s death was meant to be fate.","TWN":"第二個會死掉是一開始就注定的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"장로! 당주님 앞에서 어찌 말씀을 그리 하십니까!","JPN":"長老！　ご当主様の御前でなぜそのような話をされるのですか！","ENG":"Elder! How dare you speak ill in front of Lady Nanahara?!","TWN":"長老！您怎麼可以對堂主說這種話！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"그만……!","JPN":"そこまで……！","ENG":"Enough…!","TWN":"好了……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"그만하렴, 카나데.","JPN":"やめなさい、かなで。","ENG":"That is enough, Kanade.","TWN":"速水奏，別說了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"당주님……","JPN":"ご当主様……","ENG":"My lady...","TWN":"堂主……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"장로의 말이 맞아. 이 아이는 처음부터 살아가지 못할 운명이었다.","JPN":"長老の言うとおりだ。この子は最初から生きられない運命であった。","ENG":"She is right. The baby was destined to die.","TWN":"長老說的沒錯，這個孩子從一開始就注定要死。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"두 아이 모두 건강했다면 오히려 다른 당주들이 가만히 두고 보지 않았을 거야.","JPN":"双子が両方とも健康に生まれてきていたら、むしろ他の当主が放っておかないだろう。","ENG":"Had they been both healthy, the other family leaders would not have approved of it.","TWN":"要是二個都是健康的孩子，其他堂主一定也不會坐視不管的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"예정에 없던 가문의 아이가 태어나, 역신을 깨우리라.","JPN":"前例のない子どもが生まれ、疫病神の眠りを覚ますだろう。","ENG":"The unexpected child shall awaken the Plague God.","TWN":"不在家族預期內出生的孩子，會喚醒瘟神。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"초대 당주께서 말씀하신 경고였지요. 하야미 공도 알고 계실 텐데요.","JPN":"初代ご当主の警告でしたね。速水様もご存じのはずです。","ENG":"The first Lady Nanahara had warned us. I’m sure you are aware of it as well, Dame Kanade.","TWN":"這是初代堂主的警告，速水你應該也知道吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"저 역시 안타까우나. 구태여 화근을 살려 둘 이유는 없는 법이지요.","JPN":"私もまた残念だとは思いますが。わざわざ災いの元を生かしておく理由はありません。","ENG":"As tragic as it is, we cannot afford to take a risk.","TWN":"我也感到很遺憾，但有什麼理由留下禍根呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"카나데, 이 아이는…… 처음부터 태어나지 않은 것이다.","JPN":"かなで、この子は……最初から生まれなかったのだ。","ENG":"This child... was never born in the first place. Understood, Kanade?","TWN":"速水奏，這個孩子……根本就不該出生。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"다들 이번 일은 아무에게도 알리지 말거라. 밖으로 새어나가면 어수선해질 테니.","JPN":"皆、このことは誰にも知られぬように。外に漏れると騒がしくなるだろう。","ENG":"What happened in this place stays here. It will only bring turmoil if the others know.","TWN":"這件事不准告訴任何人，要是洩漏出去恐怕會出亂子。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주님의 뜻이 그러시다면, 그리 하지요.","JPN":"ご当主がそうおっしゃるのなら、そういたしましょう。","ENG":"As you wish, my lady.","TWN":"一切照堂主的吩咐。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"……알겠습니다, 당주님.","JPN":"……承知いたしました、ご当主様。","ENG":"...Yes, my lady.","TWN":"……是，堂主。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"이 아이는 제가 양지 바른 곳에 묻고 오도록 하겠습니다.","JPN":"この子は私が良い場所を選んで葬ってまいります。","ENG":"I will go and bury this child some place nice and quiet.","TWN":"我會找個好地方把這個孩子埋起來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"그래…… 부탁하마.","JPN":"そうか……頼んだぞ。","ENG":"Yes... Thank you.","TWN":"嗯……交給你了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"당주를 찾아라! 절대로 놓치면 안 돼!","JPN":"当主を探せ！　絶対に逃がすな！","ENG":"Find Lady Nanahara! Don’t let her escape!","TWN":"找到堂主！絕不能讓人跑了！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"쿨럭……","JPN":"ガハッ……","ENG":"*Cough...*","TWN":"咳咳……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"조금만, 조금만 버티십시오! 당주님! 정신을 잃으시면 안됩니다!","JPN":"もう少し、もう少しだけお持ちこたえください！　ご当主様！　気を失われてはいけません！","ENG":"Stay with me, my lady! You mustn’t lose consciousness!","TWN":"忍耐一下，再撐一下就好，堂主，您不能倒下！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"내가 어리석은 탓이다…… 미안하구나.","JPN":"私が愚かであったせいだ……すまない。","ENG":"This is all my fault... I am sorry.","TWN":"都怪我太愚蠢……對不起。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"카나데, 넌 사요를 줄곧 의심했지만…… 내 하잘 것 없는 정이 일을 그르쳤다.","JPN":"かなで、君はずっと小夜のことを疑っていたのに……私のくだらない情で事を見誤った。","ENG":"Kanade, you have always suspected Sayo... But my frail heart has ruined everything.","TWN":"速水奏，你一直在懷疑小夜……因為我的感情用事，事情才會變得一發不可收拾。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"아직…… 늦지 않았습니다! 여길 무사히 벗어나셔서 나중에 사요를 처벌하시지요!","JPN":"まだ……間に合います！　無事にここを切り抜け、後で小夜を処罰なさってください！","ENG":"It’s not over yet, my lady...! We will bring justice upon Sayo afterwards!","TWN":"不……還來得及！等我們安全離開這裡後，再懲罰小夜！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"뱃속에서 죽어가던 아이도…… 죽어갈 땐 이리 아팠을까?","JPN":"お腹の中で死んでいった子も……死ぬ時はこのように痛かっただろうか。","ENG":"I wonder... if my dead baby also felt pain... inside my womb...","TWN":"那孩子在我肚子裡死去時……也是這麼痛苦嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"당주님……","JPN":"ご当主様……","ENG":"My lady...","TWN":"堂主……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"네 손으로 그 아일 묻게 해서 미안하구나…… 내가 직접 묻어주지 못해 미안하다……","JPN":"君の手であの子を葬らせてすまない……私の手で葬ることができずすまない……","ENG":"I am sorry you had to go and bury her... I am sorry, my child... I should have buried you myself...","TWN":"對不起，讓你親手埋葬那孩子……對不起，沒能親手埋葬我的孩子……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"어찌 그런 말씀을 하십니까? 어서 돌아가셔서 살아 있는 따님이라도 다시 뵈어야지요.","JPN":"なぜそのようなことをおっしゃるのですか？　早くお戻りになって、生きているお嬢様にお会いください。","ENG":"Why would you say that, my lady? You must go back and reunite with your other daughter!","TWN":"堂主，您在胡說什麼？您一定要活著回去看您的女兒。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"사요의 병사가 날 찔렀을 때 내 운명이 들렸단다…… 여기서 벗어나지 못할 거라고 말이야.","JPN":"小夜の兵士が私を刺した時に私の運命が聞こえたのだ……ここから抜け出ることは叶わないと。","ENG":"I could hear my fate when Sayo’s troop stabbed me... I knew I was not going to make it out alive.","TWN":"小夜的士兵刺中我時，我便已聽見我的命運……我是無法離開這裡的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"사요 장로…… 그자의 목적은 역시 오로치를 깨우려는 것이었군요.","JPN":"小夜長老……あの者の目的はやはりオロチを呼び覚ますことだったのですね。","ENG":"Elder Sayo... So her intention was to awaken Orochi.","TWN":"小夜長老……那女人的目的果然是要喚醒大蛇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"저들의 손에 죽으면, 난 땅에 묻히지도 못한 채 역신을 깨우는 제물이 되겠지.","JPN":"あの者の手にかかって死ねば、私は土に埋められず疫病神を目覚めさせるための供物となるだろう。","ENG":"If I die in their hands, I shall become none but a mere offering to the Plague God, unable to rest in peace...","TWN":"要是我死在他們手裡，恐怕也無法入土為安，而是會成為喚醒瘟神的祭物吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"그렇게 생각을 하니…… 먼저 죽은 아이 묘비에 이름 한 자 새겨주지 못한 내가 참으로 원망스럽더구나.","JPN":"そう思うと……先に逝った子の墓石に名も刻んでやれない自分がとても憎い。","ENG":"That led me to think... that I should have at least put a name on my dead child’s tombstone.","TWN":"一想到這裡……我就恨我自己，沒能在孩子的墓碑上刻上名字。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"겨울에 태어난 아이니까…… 이름이라도 그렇게 지어줄 것을 그랬는데……","JPN":"冬に生まれた子ゆえ……名もそう付けられればよかったろうに……","ENG":"She was born in winter... I should have named her something related to it...","TWN":"那孩子是冬天出生的……早知道就該取個名字的……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"당주님은 이런 곳에서 돌아가실 분이 아닙니다.","JPN":"ご当主様はこのようなところで亡くなる方ではありません。","ENG":"You cannot die at a place like this, my lady.","TWN":"堂主，您不會死在這裡的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"사요의 무리를 꺾고 돌아가시어 내일은 그 아이에게 이름을 지어주시지요.","JPN":"小夜らに打ち勝ち、明日、あの子に名を付けてあげてください。","ENG":"We will go back and put an end to Sayo’s rebellion. You will be able to name your child tomorrow.","TWN":"等我們打敗小夜的人回去後，明天就給那孩子取名字。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_GRAND","text":{"KOREA":"카나데…….","JPN":"かなで……","ENG":"Kanade...","TWN":"速水奏……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"핏자국이다! 이 근처다!","JPN":"血痕だ！　この辺りだぞ！","ENG":"Bloodstains! Over here!","TWN":"有腳印！人就在附近！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"찾아라! 멀리 가지 못했다!","JPN":"探せ！　遠くまでは逃げていないはずだ！","ENG":"Find her! She won’t be far!","TWN":"快去找！她們應該走不遠！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"당주님은, 여기 숨어 계십시오.","JPN":"ご当主様はここに隠れていてください。","ENG":"Stay here, my lady.","TWN":"堂主，您先躲在這裡，"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"제가 배반자들을 처리하겠습니다.","JPN":"私が裏切り者を始末します。","ENG":"I’ll go take care of the betrayers.","TWN":"我去處理掉那些叛徒。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"헉…… 허억…….","JPN":"はっ……はぁ……","ENG":"*Huff...* *Huff...!*","TWN":"呼……呼呼……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이번에도 그 기억이구나.","JPN":"またあの記憶なのですね。","ENG":"It is that memory again.","TWN":"又做同樣的夢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어머님께서 태어나시던 날의…… 기억…….","JPN":"お母様が生まれた日の……記憶……","ENG":"The day of my mother’s birth...","TWN":"媽媽出生那天的……記憶……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님, 들어가도 괜찮을지요?","JPN":"ご当主様、失礼してもよろしいでしょうか。","ENG":"My lady, may I come in?","TWN":"堂主，我可以進去嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"아! 어서 들어오세요. 사나에.","JPN":"あ！　どうぞお入りください。早苗。","ENG":"Oh! Please do, Sanae.","TWN":"嗯！進來吧，早苗。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"바깥바람이 이렇게 찬데, 새벽부터 밖에 나와 계셨던 건가요?","JPN":"外の風がこんなに冷たいのに、明け方から外に出ていたのですか？","ENG":"The air is cold outside, have you been waiting since early morning?","TWN":"外面風這麼凉，你一早就跑到外面嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"전해드릴 소식이 있어 이른 시각에 찾아뵀습니다.","JPN":"お伝えすることがあり、このような早朝にまいりました。","ENG":"I had news to offer. Please excuse my intrusion.","TWN":"因為我有事要跟堂主說，才會這麼早來找您。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……그나저나 식은 땀을 흘리셨군요. 악몽이라도 꾸신 겁니까?","JPN":"……それにしても冷や汗をかかれていますね。悪い夢でも見られたのですか？","ENG":"...You are sweating. Did you have a nightmare?","TWN":"……不過您怎麼在冒冷汗，是做惡夢嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그냥 꿈이 아닙니다. 이건 과거에 실제로 벌어졌던 사건이니까요.","JPN":"ただの夢ではありません。これは過去に実際あった事件ですから。","ENG":"It was not just a dream. It was what had happened in the past.","TWN":"不只是夢，是過去真實發生過的事。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제 어머니의 가면에서 읽으셨다던 그 기억인 모양이군요.","JPN":"私の母の仮面からお読みになったというあの記憶のようですね。","ENG":"It must be the memory that you have read from my mother’s mask.","TWN":"應該是指從家母的面具讀到的記憶吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"잠자리에 들 때마다 같은 기억이 반복되는 것은 바람의 목소리가 당주님께 무언가를 말하려는 것이 아닐지요.","JPN":"寝床に入るたびに同じ記憶がくり返されるということは、風の声がご当主様に何かを伝えようとしているのではないでしょうか。","ENG":"If the same memory repeats itself every night... Then perhaps the voice of wind is trying to tell you something?","TWN":"每次入睡後就會重複做同樣的夢，這會不會是風聲想要對堂主說什麼呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사나에……, 바람의 목소리는 이미 저를 떠났어요.","JPN":"早苗……風の声はすでに私のそばを離れました。","ENG":"Sanae... the voice of wind has long past left me.","TWN":"早苗……風聲早就離我而去。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이젠 사물을 통해 기억을 읽을 수도, 꿈을 통해 미래를 들을 수도 없습니다.","JPN":"もう物を通じて記憶を読むことも、夢を通じて未来を聞くこともできません。","ENG":"I can no longer read memories from objects, nor see the future through dreams.","TWN":"我再也無法藉由事物讀取記憶，也無法透過夢境預知未來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그 날, 오로치를 막기 위해 신력을 쓴 뒤로는 말이죠.","JPN":"あの日、オロチを阻止するために神力を使った後からです。","ENG":"After that day, when I used my divine powers to stop Orochi...","TWN":"自從那天用神力阻止大蛇後便是如此。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 제가 아직 당주 자리에 있는 것은, 마땅한 후계가 없어서일 뿐입니다.","JPN":"そんな私がいまだ当主である理由は、適当な後継者がいないからにすぎません。","ENG":"The reason why I am still the head of the family is because we are yet to have a rightful heir.","TWN":"而我之所以還能夠做在堂主的位置上，只是因為暫時沒有合適的繼位人選而已。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저와 다른 이들을 살린 것을 후회하십니까?","JPN":"私と他の者たちを救ったことを後悔されていませんか？","ENG":"Do you regret saving me and the others, my lady?","TWN":"您後悔出手救我們嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 건 후회하지 않습니다! 절대로요!","JPN":"それは後悔していません！　決して！","ENG":"I would never feel that way! Never!","TWN":"當然不後悔！我絕不後悔！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만…… 그런 결정을 대가로 바람의 목소리를 듣지 못하게 됐다는 건, 선조들께서 저의 자격을 인정하지 않으신다는 뜻이니까요.","JPN":"しかし……そのような決定と引き換えに風の声を聞けなくなったということは、ご先祖様が私にその資格がないとされたという意味ですから。","ENG":"However... the fact that I am now incapable of hearing the voice of wind must mean that I am no longer in favor of our ancestors.","TWN":"只是……我做出這樣的決定後，代價是再也聽不到風聲，這就表示祖先不認同我的資格。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"허나 그 날 당주님께서 신력을 쓰지 않았다면 오로치를 봉인할 수는 없었을 터.","JPN":"ですがあの日、ご当主様が神力をお使いにならなかったなら、オロチを封印することもできなかったはずです。","ENG":"Alas, my lady. Had it not been for you and your divine powers, Orochi would have never been sealed.","TWN":"不過要是那天堂主沒有使用神力，是無法封印住大蛇的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그 덕에 변절자와의 악연을 끊고, 희생을 최소화할 수 있었습니다.","JPN":"おかげで裏切り者との悪縁を断ち、犠牲を最小限に抑えることもできました。","ENG":"Thanks to you, we were able to cut ties with the traitor and minimize the damage.","TWN":"也因為這樣，才能斷開與叛徒之見的孽緣，也將犧牲降到最低。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"무엇이 옳은 결정이고 더 나은 결과였을지는 이미 알고 계시지 않습니까?","JPN":"何が正しい決定であり、より良い結果であるかはすでにご存じではありませんか？","ENG":"You already know that you made the right choice. The most rational choice.","TWN":"什麼才是正確的決定，什麼才是更好的結果，相信堂主心裡也很明白不是嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇죠. 저는 후회하지 않아요.","JPN":"そうですね。私は後悔しません。","ENG":"You are right. I do not regret it.","TWN":"沒錯，我不後悔。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"약한 소리 해서 미안해요, 사나에.","JPN":"弱音を吐いてしまってごめんなさい、早苗。","ENG":"I am sorry for saying things like this, Sanae.","TWN":"早苗，對不起，說這些沒出息的話。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그런 말씀 마시길. 이 사람이야말로 당주님께 많은 신세를 졌으니까요.","JPN":"そんなことはおっしゃらず。私こそご当主様にはたくさんの恩がございますから。","ENG":"Please do not be. It is this humble servant who has been saved by your grace.","TWN":"堂主別這麼說，是我欠堂主太多。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키 당주의 재판이 오늘 마무리되었다고 합니다.","JPN":"覇吐当主の裁判が今日終わったそうです。","ENG":"They say Elder Habaki’s trial ends today.","TWN":"對幅木堂主的裁決今天就會結案，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"내일 중에 관리국 관할 수감소로 이감된다고 하더군요.","JPN":"明日には管理局管轄の収容所に移管されるということです。","ENG":"Tomorrow, he will be sent to prison under the Administration’s watch.","TWN":"明天他就會移監至管理局管轄的監獄。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지금까지 밝혀진 정황들이 모두 그 자를 가리키고 있습니다.","JPN":"今まで明らかになった状況はすべてあの者を指し示しています。","ENG":"All evidence leads up to him.","TWN":"目前查出來的證據都指向他。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"진실을 알아내려면 이번이 마지막 기회이겠군요.","JPN":"真実を知るためにはこれが最後の機会になるでしょう。","ENG":"Perhaps this will be the last chance to seek out the truth.","TWN":"看來要查清真相，這次是最後的機會。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……알겠어요. 제가 하바키를 만나보겠습니다.","JPN":"……わかりました。私が覇吐に会ってみます。","ENG":"...Very well. I will go see him.","TWN":"……好，我要親自去見幅木。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};